import static org.junit.jupiter.api.Assertions.assertEquals;

import com.google.gson.internal.bind.DefaultDateTypeAdapter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.text.DateFormat;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;

public class DefaultDateTypeAdapterTest {

  private DefaultDateTypeAdapter<Date> adapter;

  @BeforeEach
  public void setUp() throws Exception {
    // Use reflection to invoke private constructor: DefaultDateTypeAdapter(DateType<T> dateType, String datePattern)
    Class<?> clazz = DefaultDateTypeAdapter.class;
    var ctor = clazz.getDeclaredConstructors()[0];
    ctor.setAccessible(true);
    // Passing null for dateType because we do not use it in toString()
    adapter = (DefaultDateTypeAdapter<Date>) ctor.newInstance(null, "yyyy-MM-dd");

    // Clear and set dateFormats list with a SimpleDateFormat instance for first test
    Field dateFormatsField = clazz.getDeclaredField("dateFormats");
    dateFormatsField.setAccessible(true);
    List<DateFormat> dateFormats = new ArrayList<>();
    dateFormats.add(new SimpleDateFormat("yyyy-MM-dd"));
    dateFormatsField.set(adapter, dateFormats);
  }

  @Test
  public void testToString_withSimpleDateFormat() {
    String expected = "DefaultDateTypeAdapter(yyyy-MM-dd)";
    assertEquals(expected, adapter.toString());
  }

  @Test
  public void testToString_withNonSimpleDateFormat() throws Exception {
    // Replace dateFormats[0] with a DateFormat subclass that is not SimpleDateFormat
    Class<?> clazz = DefaultDateTypeAdapter.class;
    Field dateFormatsField = clazz.getDeclaredField("dateFormats");
    dateFormatsField.setAccessible(true);
    List<DateFormat> dateFormats = new ArrayList<>();
    DateFormat anonymousDateFormat = new DateFormat() {
      @Override
      public StringBuffer format(Date date, StringBuffer toAppendTo, java.text.FieldPosition fieldPosition) {
        return null;
      }
      @Override
      public Date parse(String source, ParsePosition pos) {
        return null;
      }
      @Override
      public String getClass().getSimpleName() {
        return "CustomDateFormat";
      }
    };
    // The above override of getClass() is invalid, so instead create a named subclass:
    class CustomDateFormat extends DateFormat {
      @Override
      public StringBuffer format(Date date, StringBuffer toAppendTo, java.text.FieldPosition fieldPosition) {
        return null;
      }
      @Override
      public Date parse(String source, ParsePosition pos) {
        return null;
      }
    }
    dateFormats.add(new CustomDateFormat());
    dateFormatsField.set(adapter, dateFormats);

    String expected = "DefaultDateTypeAdapter(CustomDateFormat)";
    assertEquals(expected, adapter.toString());
  }
}
